 23→const SETTINGS_TABS: SettingsTab[] = [
 24→  'general',
 25→  'extensions',
 26→  'advanced',
 27→];
 28→
 29→function isSettingsTab(value: string): value is SettingsTab {
 30→  return SETTINGS_TABS.includes(value as SettingsTab);
 31→}
