105→function ToggleSwitch({
106→  checked,
107→  onChange,
108→  label,
109→}: {
110→  checked: boolean;
111→  onChange: (checked: boolean) => void;
112→  label: string;
113→}) {
114→  return (
115→    <label className="settings-toggle">
116→      <input
117→        type="checkbox"
118→        className="settings-toggle__input"
119→        checked={checked}
120→        onChange={e => onChange(e.target.checked)}
121→        aria-label={label}
122→      />
123→      <div className="settings-toggle__track" />
124→      <div className="settings-toggle__knob" />
125→    </label>
126→  );
127→}
