255→          }
256→          options={APPEARANCE_OPTIONS}
257→        />
258→        <FormDropdown
259→          label="Window Width"
260→          value={settings.windowWidth}
261→          onChange={v =>
262→            onSettingsChange({
263→              ...settings,
