318→function ExtensionsTab({
319→  extensions,
320→  onToggle,
321→  query,
322→}: {
323→  extensions: ExtensionEntry[];
324→  onToggle: (id: string) => void;
325→  query: string;
326→}) {
327→  const filtered = useMemo(() => {
328→    if (!query) return extensions;
329→    const lower = query.toLowerCase();
330→    return extensions.filter(
331→      ext =>
332→        ext.name.toLowerCase().includes(lower) ||
333→        ext.description.toLowerCase().includes(lower) ||
334→        ext.author.toLowerCase().includes(lower),
335→    );
336→  }, [
337→    extensions,
338→    query,
339→  ]);
340→
341→  const raycastExts = filtered.filter(ext => ext.author === 'Raycast');
342→  const communityExts = filtered.filter(ext => ext.author !== 'Raycast');
343→
344→  return (
345→    <div className="settings-view__extensions">
346→      {filtered.length === 0 ? (
347→        <EmptyState
348→          icon={<SearchEmptyIcon />}
349→          title="No Extensions Found"
350→          description="Try a different search term"
351→        />
352→      ) : (
353→        <>
354→          {raycastExts.length > 0 && (
355→            <div className="settings-section">
356→              <div className="settings-section__title">Built-in</div>
357→              {raycastExts.map(ext => (
358→                <div
359→                  key={ext.id}
360→                  className="settings-extension"
361→                  onClick={() => onToggle(ext.id)}
362→                  role="button"
363→                  tabIndex={0}
364→                  onKeyDown={e => {
365→                    if (e.key === 'Enter' || e.key === ' ') {
366→                      e.preventDefault();
367→                      onToggle(ext.id);
368→                    }
369→                  }}
370→                >
371→                  <div className="settings-extension__icon">{ext.icon()}</div>
372→                  <div className="settings-extension__info">
373→                    <div className="settings-extension__name">{ext.name}</div>
374→                    <div className="settings-extension__meta">
375→                      {ext.description}
376→                    </div>
377→                  </div>
378→                  <div className="settings-extension__toggle">
379→                    <ToggleSwitch
380→                      checked={ext.enabled}
381→                      onChange={() => onToggle(ext.id)}
382→                      label={`Toggle ${ext.name}`}
383→                    />
384→                  </div>
385→                </div>
386→              ))}
387→            </div>
388→          )}
389→          {communityExts.length > 0 && (
390→            <div className="settings-section">
391→              <div className="settings-section__title">Community</div>
392→              {communityExts.map(ext => (
393→                <div
394→                  key={ext.id}
395→                  className="settings-extension"
396→                  onClick={() => onToggle(ext.id)}
397→                  role="button"
398→                  tabIndex={0}
399→                  onKeyDown={e => {
400→                    if (e.key === 'Enter' || e.key === ' ') {
401→                      e.preventDefault();
402→                      onToggle(ext.id);
403→                    }
404→                  }}
405→                >
406→                  <div className="settings-extension__icon">{ext.icon()}</div>
407→                  <div className="settings-extension__info">
408→                    <div className="settings-extension__name">{ext.name}</div>
409→                    <div className="settings-extension__meta">
410→                      {ext.description} &middot; {ext.author}
411→                    </div>
412→                  </div>
413→                  <div className="settings-extension__toggle">
414→                    <ToggleSwitch
415→                      checked={ext.enabled}
416→                      onChange={() => onToggle(ext.id)}
417→                      label={`Toggle ${ext.name}`}
418→                    />
419→                  </div>
420→                </div>
421→              ))}
422→            </div>
423→          )}
424→        </>
425→      )}
426→    </div>
427→  );
428→}
