430→function AdvancedTab({
431→  onExport,
432→  onImport,
433→  onClearCache,
434→  onResetAll,
435→}: {
436→  onExport: () => void;
437→  onImport: () => void;
438→  onClearCache: () => void;
439→  onResetAll: () => void;
