441→  return (
442→    <div className="settings-view__advanced">
443→      <div className="settings-section">
444→        <div className="settings-section__title">Data</div>
445→        <div
446→          className="settings-action-row"
447→          onClick={onExport}
448→          role="button"
449→          tabIndex={0}
450→          onKeyDown={e => {
451→            if (e.key === 'Enter' || e.key === ' ') {
452→              e.preventDefault();
453→              onExport();
454→            }
455→          }}
456→        >
457→          <div className="settings-action-row__icon">
458→            <ExportIcon />
459→          </div>
460→          <span className="settings-action-row__label">Export Settings</span>
461→          <span className="settings-action-row__hint">Save as JSON</span>
462→        </div>
463→        <div
464→          className="settings-action-row"
465→          onClick={onImport}
466→          role="button"
467→          tabIndex={0}
468→          onKeyDown={e => {
469→            if (e.key === 'Enter' || e.key === ' ') {
470→              e.preventDefault();
471→              onImport();
472→            }
473→          }}
474→        >
475→          <div className="settings-action-row__icon">
476→            <ImportIcon />
477→          </div>
478→          <span className="settings-action-row__label">Import Settings</span>
479→          <span className="settings-action-row__hint">Load from JSON</span>
480→        </div>
481→      </div>
482→      <div className="settings-section">
483→        <div className="settings-section__title">Maintenance</div>
484→        <div
485→          className="settings-action-row"
486→          onClick={onClearCache}
487→          role="button"
488→          tabIndex={0}
489→          onKeyDown={e => {
490→            if (e.key === 'Enter' || e.key === ' ') {
491→              e.preventDefault();
492→              onClearCache();
493→            }
494→          }}
495→        >
496→          <div className="settings-action-row__icon">
497→            <RefreshIconSmall />
498→          </div>
499→          <span className="settings-action-row__label">Clear Cache</span>
500→          <span className="settings-action-row__hint">Free up space</span>
501→        </div>
502→        <div
503→          className="settings-action-row settings-action-row--destructive"
504→          onClick={onResetAll}
505→          role="button"
506→          tabIndex={0}
507→          onKeyDown={e => {
508→            if (e.key === 'Enter' || e.key === ' ') {
509→              e.preventDefault();
510→              onResetAll();
511→            }
512→          }}
513→        >
514→          <div className="settings-action-row__icon">
515→            <TrashIconSmall />
516→          </div>
517→          <span className="settings-action-row__label">Reset All Settings</span>
518→        </div>
519→      </div>
520→    </div>
521→  );
522→}
