 52→function filterSections(sections: SectionData[], query: string): SectionData[] {
 53→  if (!query) return sections;
 54→  const lower = query.toLowerCase();
 55→  return sections
 56→    .map(section => ({
 57→      ...section,
 58→      items: section.items.filter(
 59→        item =>
 60→          item.title.toLowerCase().includes(lower) ||
 61→          item.subtitle?.toLowerCase().includes(lower),
 62→      ),
 63→    }))
 64→    .filter(section => section.items.length > 0);
 65→}
 66→
 67→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 68→  if (!query) return colors;
 69→  const lower = query.toLowerCase();
 70→  return colors.filter(
 71→    c =>
 72→      c.title.toLowerCase().includes(lower) ||
 73→      c.subtitle?.toLowerCase().includes(lower),
 74→  );
 75→}
 76→
 77→function flattenItems(sections: SectionData[]): ListItemData[] {
 78→  return sections.flatMap(s => s.items);
