857→            </div>
858→          </div>
859→        ) : (
860→          <div
861→            className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
862→          >
863→            <div className="command-palette__list-container">
864→              {allItems.length === 0 ? (
865→                <EmptyState
866→                  icon={<SearchIcon />}
867→                  title="No Results"
868→                  description="Try a different search term"
869→                />
870→              ) : (
871→                <List
872→                  itemCount={allItems.length}
873→                  onActiveIndexChange={handleActiveIndexChange}
874→                  onAction={handleDrillIn}
875→                >
876→                  {(() => {
877→                    let globalIndex = 0;
878→                    return (
879→                      <>
880→                        {calculatorResult && (
881→                          <ListSection title="Result">
882→                            <ListItem
883→                              index={globalIndex++}
884→                              title={`= ${calculatorResult}`}
885→                              subtitle={query.trim()}
886→                              icon={<CalculatorIcon />}
887→                              accessories={[{ text: 'Copy' }]}
888→                            />
889→                          </ListSection>
890→                        )}
891→                        {filtered.map(section => (
892→                          <ListSection
893→                            key={section.title}
894→                            title={section.title}
895→                          >
896→                            {section.items.map(item => {
897→                              const idx = globalIndex++;
898→                              return (
899→                                <ListItem
900→                                  key={item.id}
901→                                  index={idx}
902→                                  title={item.title}
903→                                  subtitle={item.subtitle}
904→                                  icon={item.icon}
905→                                  accessories={item.accessories}
906→                                />
907→                              );
908→                            })}
909→                          </ListSection>
910→                        ))}
911→                      </>
912→                    );
913→                  })()}
914→                </List>
915→              )}
916→            </div>
917→            {detail && (
918→              <Detail
919→                markdown={detail.markdown}
920→                metadata={
921→                  detail.metadata ? (
922→                    <DetailMetadata>
923→                      {detail.metadata.map(renderMetadataEntry)}
924→                    </DetailMetadata>
925→                  ) : undefined
926→                }
927→              />
928→            )}
929→          </div>
930→        )}
931→        {!isFullView && (
932→          <ActionPanel
933→            contextLabel={contextLabel}
934→            actions={[
935→              {
936→                label: isCalculatorSelected ? 'Copy Result' : 'Open',
937→                shortcut: <Kbd keys={['↵']} />,
938→              },
939→              {
940→                label: 'Actions',
941→                shortcut: (
942→                  <Kbd
943→                    keys={[
944→                      '⌘',
945→                      'K',
946→                    ]}
947→                  />
948→                ),
949→                onClick: toggleActions,
950→              },
951→            ]}
952→            dropdownOpen={actionsOpen}
953→            dropdownSections={dropdownSections}
954→            onDropdownClose={closeActions}
955→          />
956→        )}
957→        {!isFullView && quickLookOpen && selectedItem?.detail && (
958→          <QuickLook title={selectedItem.title} onClose={closeQuickLook}>
959→            <Detail
960→              markdown={selectedItem.detail.markdown}
961→              metadata={
962→                selectedItem.detail.metadata ? (
963→                  <DetailMetadata>
964→                    {selectedItem.detail.metadata.map(renderMetadataEntry)}
965→                  </DetailMetadata>
966→                ) : undefined
967→              }
968→            />
969→          </QuickLook>
970→        )}
971→        {!isFullView && alertState && (
972→          <Alert
973→            title={alertState.title}
974→            message={alertState.message}
975→            icon={alertState.icon}
976→            primaryAction={alertState.primaryAction}
977→            dismissAction={alertState.dismissAction}
978→            onDismiss={dismissAlert}
979→          />
980→        )}
981→        <ToastContainer toasts={toasts} onDismiss={hideToast} />
982→        {!isFullView && <HUDContainer items={hudItems} />}
983→      </CommandPalette>
984→    </NavigationContextProvider>
985→  );
986→}
